const root = createRoot(document.getElementById("root"));

root.render(
  <Auth0Provider
    domain="dev-p3jaaxsj5w68wv7t.us.auth0.com"
    clientId="tXv9SRym2LCEhz54cSsTJzpHaiayneAi"
    authorizationParams={{
      redirect_uri: window.location.origin,
    }}
  >
    <App />
  </Auth0Provider>
);
